class Node:
    def __init__(self, char):
        self.char = char.lower()
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = Node(char)
        else:
            self._insert_recursive(self.root, char)

    def _insert_recursive(self, node, char):
        if char < node.char:
            if node.left is None:
                node.left = Node(char)
            else:
                self._insert_recursive(node.left, char)
        elif char > node.char:
            if node.right is None:
                node.right = Node(char)
            else:
                self._insert_recursive(node.right, char)

def process_sequence(sequence):
    bst = BST()
    def process_char(index):
        if index >= len(sequence):
            return
        char = sequence[index]
        if not bst.root or not has_char(bst.root, char):
            bst.insert(char)
        process_char(index + 1)
    process_char(0)
    return bst

def has_char(node, char):
    if node is None:
        return False
    if node.char == char:
        return True
    elif char < node.char:
        return has_char(node.left, char)
    else:
        return has_char(node.right, char)

